import sys
input = sys.stdin.readline

def feasible(h, m):
    n = len(h)
    a = h[:]
    for i in range(2, n):
        deficit = m - a[i-2]
        if deficit > 0:
            d = (deficit + 1) // 2
        else:
            d = 0
        max_d = a[i] // 3
        if d > max_d:
            return False
        # Use maximum d to help a[i-1] as much as possible
        d = max_d
        a[i] -= 3 * d
        a[i-1] += d
        a[i-2] += 2 * d
    return all(x >= m for x in a)

def solve():
    n = int(input())
    h = list(map(int, input().split()))
    lo, hi = 0, sum(h) // n
    ans = 0
    while lo <= hi:
        mid = (lo + hi) // 2
        if feasible(h, mid):
            ans = mid
            lo = mid + 1
        else:
            hi = mid - 1
    print(ans)

t = int(input())
